module top_module (
    input clk,
    input reset,
    input d,
    input enable,
    output q );reg unused_q_reg;

    always @(posedge clk) begin
        if (reset)
            unused_q_reg <= 1'b0;
        else if (enable)
            unused_q_reg <= d;
    end

    assign q = unused_q_reg;

endmodule
